INSERT INTO "drug_interactions" ("drug1", "drug2", "severity", "description", "recommendation", "source") VALUES
('Лизиноприл', 'Ибупрофен', 'major', 'НПВС снижают антигипертензивный эффект ингибиторов АПФ и повышают риск острой почечной недостаточности.', 'Избегайте совместного применения. При необходимости замените ибупрофен на парацетамол.', 'AIVITA AI'),
('Варфарин', 'Аспирин', 'critical', 'Комбинация резко повышает риск кровотечений — желудочно-кишечных и внутричерепных.', 'Комбинация требует строгого медицинского наблюдения. Не принимайте без назначения врача. Регулярно контролируйте МНО.', 'AIVITA AI'),
('Метформин', 'Алкоголь', 'major', 'Алкоголь повышает риск лактоацидоза на фоне метформина — потенциально смертельного осложнения.', 'Полностью исключите алкоголь при приёме метформина.', 'AIVITA AI'),
('Амлодипин', 'Симвастатин', 'moderate', 'Амлодипин повышает концентрацию симвастатина в крови, увеличивая риск миопатии и рабдомиолиза.', 'Дозу симвастатина не следует превышать 20 мг/сут при совместном приёме. Рассмотрите замену статина.', 'AIVITA AI'),
('Омепразол', 'Клопидогрел', 'major', 'Омепразол угнетает CYP2C19, снижая активацию клопидогрела на 40–50%, что ухудшает его антиагрегантный эффект.', 'Замените омепразол на пантопразол — он меньше влияет на активацию клопидогрела.', 'AIVITA AI'),
('Метотрексат', 'Ибупрофен', 'critical', 'НПВС снижают почечный клиренс метотрексата, резко повышая его токсичность (угнетение кроветворения, мукозит).', 'Категорически противопоказано. Используйте только разрешённые анальгетики под контролем врача.', 'AIVITA AI'),
('Амиодарон', 'Варфарин', 'critical', 'Амиодарон ингибирует метаболизм варфарина, значительно усиливая антикоагулянтный эффект и риск кровотечений.', 'Необходим регулярный мониторинг МНО. Снизьте дозу варфарина на 30–50% под контролем врача.', 'AIVITA AI'),
('Ципрофлоксацин', 'Антацид', 'moderate', 'Антациды (магний, кальций, алюминий) хелатируют фторхинолоны, снижая их всасывание на 50–90%.', 'Принимайте ципрофлоксацин за 2 часа до или через 6 часов после антацидов.', 'AIVITA AI'),
('Каптоприл', 'Калий', 'major', 'Ингибиторы АПФ задерживают калий. Дополнительный приём препаратов калия может вызвать гиперкалиемию — угрозу аритмий.', 'Контролируйте уровень калия. Избегайте добавок калия без назначения врача.', 'AIVITA AI'),
('Дигоксин', 'Амиодарон', 'major', 'Амиодарон повышает концентрацию дигоксина в 2 раза, провоцируя дигиталисную токсичность (тошнота, аритмии, зрительные нарушения).', 'Снизьте дозу дигоксина вдвое при назначении амиодарона. Регулярно контролируйте концентрацию дигоксина.', 'AIVITA AI'),
('Флуоксетин', 'Трамадол', 'major', 'Оба препарата повышают серотонин — риск серотонинового синдрома (гипертермия, судороги, ажитация).', 'Избегайте совместного применения. При необходимости замените один из препаратов.', 'AIVITA AI'),
('Левотироксин', 'Кальций', 'moderate', 'Кальций образует нерастворимые комплексы с левотироксином, снижая его всасывание на 20–40%.', 'Принимайте левотироксин натощак, а кальций — минимум через 4 часа.', 'AIVITA AI'),
('Метформин', 'Рентгенконтраст', 'major', 'Йодсодержащие контрасты нарушают выведение метформина, повышая риск лактоацидоза.', 'Отмените метформин за 48 часов до введения контраста и не возобновляйте 48 часов после (при нормальной функции почек).', 'AIVITA AI'),
('Азитромицин', 'Варфарин', 'major', 'Азитромицин подавляет кишечную флору, участвующую в метаболизме витамина K, усиливая действие варфарина.', 'Контролируйте МНО во время и после курса азитромицина. Возможна коррекция дозы варфарина.', 'AIVITA AI'),
('Силденафил', 'Нитраты', 'critical', 'Комбинация вызывает резкую гипотензию, возможна потеря сознания и коронарная недостаточность.', 'Абсолютно противопоказано. Нельзя принимать силденафил при любом применении нитратов.', 'AIVITA AI'),
('Аторвастатин', 'Кларитромицин', 'major', 'Кларитромицин ингибирует CYP3A4, повышая уровень статина в 10 раз — риск рабдомиолиза.', 'Временно отмените аторвастатин на период антибиотикотерапии. Замените на правастатин или розувастатин.', 'AIVITA AI'),
('Преднизолон', 'Ибупрофен', 'major', 'Комбинация стероида и НПВС резко повышает риск желудочно-кишечных язв и кровотечений.', 'Избегайте совместного применения. При необходимости используйте парацетамол и добавьте гастропротектор (омепразол).', 'AIVITA AI'),
('Лозартан', 'Спиронолактон', 'moderate', 'Оба препарата задерживают калий — риск гиперкалиемии, особенно при почечной недостаточности.', 'Регулярно контролируйте уровень калия и функцию почек. Снизьте потребление калийсодержащих продуктов.', 'AIVITA AI'),
('Парацетамол', 'Алкоголь', 'major', 'Регулярное употребление алкоголя усиливает гепатотоксичность парацетамола — риск острой печёночной недостаточности.', 'Не превышайте 2 г/сут парацетамола при регулярном употреблении алкоголя. Лучше исключить алкоголь.', 'AIVITA AI'),
('Метронидазол', 'Алкоголь', 'major', 'Вызывает дисульфирамоподобную реакцию: тошнота, рвота, тахикардия, покраснение, падение давления.', 'Полностью исключите алкоголь во время лечения и 48 часов после его окончания.', 'AIVITA AI')
